text-scene.text:
Rows of strange data appeared on the screen:

Aria | {engine_part, fuel_cell, toolkit}

Borin | {navigation_chip, fuel_cell}

Ciri | {repair_kit, oxygen_tank, toolkit}

select-scene.sql-solution:
SELECT item, COUNT(*) AS item_count
FROM (
    SELECT UNNEST(inventory) AS item FROM adventurers
) AS expanded
GROUP BY item
ORDER BY item_count DESC;

select-scene.sql-placeholder:
SELECT item, ... AS item_count
FROM (
    SELECT UNNEST(inventory) AS item FROM adventurers
) AS expanded
GROUP BY item
ORDER BY item_count DESC;

manipulate-scene.sql-solution:
UPDATE adventurers
SET inventory = array_append(inventory, 'shield_module')
WHERE name = 'Dorn';

game.initial-sql-script:
-- SQL Island: The Escape Protocol -- Database setup
CREATE TABLE adventurers ( name TEXT PRIMARY KEY, inventory TEXT[] );
INSERT INTO adventurers (name, inventory) VALUES ('Aria', ARRAY['engine_part', 'fuel_cell', 'toolkit']), ('Borin', ARRAY['navigation_chip', 'fuel_cell']), ('Ciri', ARRAY['repair_kit', 'oxygen_tank', 'toolkit']), ('Dorn', ARRAY['fuel_cell', 'repair_kit', 'engine_part', 'navigation_chip']), ('Elva', ARRAY['oxygen_tank']);
